def tags = null;
try { tags = ctx['kibana']['alert']['rule']['tags']; } catch (Exception e) {}
if (tags == null) { return; }
for (def tag : tags) {
  if (tag instanceof String && tag.matches('Cat-[A-K]')) {
    if (ctx['m_26_14'] == null) { ctx['m_26_14'] = new HashMap(); }
    ctx['m_26_14']['category'] = tag;
    return;
  }
}
if (ctx['m_26_14'] == null) { ctx['m_26_14'] = new HashMap(); }
ctx['m_26_14']['category'] = 'Cat-Unknown';
